import{_ as t,c as a,o as r,ak as o}from"./chunks/framework.B0TWM2iJ.js";const u=JSON.parse('{"title":"Theming","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/theme.md","filePath":"user-guide/theme.md","lastUpdated":1776845066000}'),s={name:"user-guide/theme.md"};function i(n,e,l,c,d,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="theming" tabindex="-1">Theming <a class="header-anchor" href="#theming" aria-label="Permalink to “Theming”">​</a></h1><p>Customise the appearance of your Aire Innovate products by updating logos, background images, and application colour palettes.</p><p>The Theming page is divided into two tabs: <strong>Images</strong> and <strong>Colours</strong>.</p><h2 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to “Images”">​</a></h2><p>Update the primary branding assets used throughout the application.</p><p>Actions available:</p><ul><li><strong>Upload</strong> — Add a new image if none exists</li><li><strong>Replace</strong> — Swap the current image with a new file</li><li><strong>Remove</strong> — Clear the current image and revert to the default branding</li></ul><div class="tip custom-block"><p class="custom-block-title">Supported formats</p><p>PNG, JPEG, and WebP.</p></div><h3 id="primary-logo" tabindex="-1">Primary Logo <a class="header-anchor" href="#primary-logo" aria-label="Permalink to “Primary Logo”">​</a></h3><p>Upload or replace the logo displayed in AireFrame.</p><p>The recommended logo size is dependent on your layout, but high-resolution files are preferred for crisp rendering.</p><h3 id="login-background-image" tabindex="-1">Login Background Image <a class="header-anchor" href="#login-background-image" aria-label="Permalink to “Login Background Image”">​</a></h3><p>Customise the image shown behind the login form.</p><p>This is optional and can be used for:</p><ul><li>Organisational branding</li><li>Hospital or trust imagery</li><li>Campaign or seasonal backgrounds</li></ul><p>The preview area shows whether an image is currently set.</p><h2 id="colours" tabindex="-1">Colours <a class="header-anchor" href="#colours" aria-label="Permalink to “Colours”">​</a></h2><p>Control the look and feel of AireFrame by selecting from preset themes or creating your own colour set.</p><h3 id="preset-themes" tabindex="-1">Preset Themes <a class="header-anchor" href="#preset-themes" aria-label="Permalink to “Preset Themes”">​</a></h3><p>Choose from predefined, professionally-designed themes:</p><ul><li><strong>AireFrame Theme</strong> — Default colours for Aire Innovate</li><li><strong>NHS Styled Theme</strong> — Based on NHS design standards</li><li><strong>GDS Styled Theme</strong> — Inspired by UK Government Design System colours</li></ul><p>Each theme preview shows examples of headings, text, components, and accents so you know exactly what the palette will look like.</p><p>Selecting a preset will automatically apply the associated colour values.</p><h3 id="customise-theme" tabindex="-1">Customise Theme <a class="header-anchor" href="#customise-theme" aria-label="Permalink to “Customise Theme”">​</a></h3><p>For full control, manually configure your colour palette:</p><ul><li><strong>Primary</strong> — The dominant interface colour (buttons, highlights, links)</li><li><strong>Secondary</strong> — Supporting accents</li><li><strong>Background</strong> — Page background colour</li><li><strong>Primary Text</strong> — The dominant text colour (titles, headings)</li><li><strong>Secondary Text</strong> — Supporting text accents (subtitles)</li></ul><h3 id="alert-colours" tabindex="-1">Alert Colours <a class="header-anchor" href="#alert-colours" aria-label="Permalink to “Alert Colours”">​</a></h3><p>Configure the colours used for alerts across AireBlocks products such as AireForms. These colours control the appearance of contextual alerts and hightlights that communicate status information to users.</p><ul><li><strong>Information</strong> — Used for informational messages and general notices</li><li><strong>Success</strong> — Used to confirm a successful action or positive outcome</li><li><strong>Warning</strong> — Used to highlight something that requires attention but is not critical</li><li><strong>Danger</strong> — Used for errors or critical issues that need immediate action</li></ul><p>Each preset theme includes sensible defaults for these colours, but they can be customised individually to match your organisation&#39;s branding or accessibility requirements.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The alert colour preview shows how each alert will appear.</p></div><h2 id="wcag-accessibility-checking" tabindex="-1">WCAG Accessibility Checking <a class="header-anchor" href="#wcag-accessibility-checking" aria-label="Permalink to “WCAG Accessibility Checking”">​</a></h2><p>When customising colours, the configurator automatically validates your palette against <a href="https://www.w3.org/TR/WCAG21/" target="_blank" rel="noreferrer">WCAG 2.1</a> contrast requirements. This helps ensure that text and UI elements remain readable for all users, including those with visual impairments.</p><div class="info custom-block"><p class="custom-block-title">What is WCAG?</p><p>The Web Content Accessibility Guidelines (WCAG) define minimum contrast ratios between foreground and background colours:</p><ul><li><strong>AA Large</strong> — 3:1 ratio for large text and UI components</li><li><strong>AA</strong> — 4.5:1 ratio for normal-sized text (the standard target)</li><li><strong>AAA</strong> — 7:1 ratio for enhanced contrast</li></ul></div><h3 id="accessibility-score" tabindex="-1">Accessibility Score <a class="header-anchor" href="#accessibility-score" aria-label="Permalink to “Accessibility Score”">​</a></h3><p>As you adjust colours, an accessibility summary appears alongside your chosen theme showing:</p><ul><li>A <strong>score</strong> indicating how many colour pairs pass (e.g. <em>8 / 10</em>)</li><li>The number of <strong>WCAG issues</strong> found</li><li>A coloured border that glows green when all pairs pass, or highlights issues when failures are detected</li></ul><h3 id="contrast-breakdown-table" tabindex="-1">Contrast Breakdown Table <a class="header-anchor" href="#contrast-breakdown-table" aria-label="Permalink to “Contrast Breakdown Table”">​</a></h3><p>The <strong>Accessibility</strong> section displays a full breakdown table of every colour pair that is checked. Pairs are grouped into three categories:</p><p><strong>App Colours</strong></p><table tabindex="0"><thead><tr><th>Pair</th><th>What it checks</th></tr></thead><tbody><tr><td>Primary / Background</td><td>Primary colour against the page background</td></tr><tr><td>Secondary / Background</td><td>Secondary colour against the page background</td></tr><tr><td>Text / Primary</td><td>Auto-selected text colour on primary surfaces</td></tr><tr><td>Text / Secondary</td><td>Auto-selected text colour on secondary surfaces</td></tr></tbody></table><p><strong>Text Colours</strong></p><table tabindex="0"><thead><tr><th>Pair</th><th>What it checks</th></tr></thead><tbody><tr><td>Primary Text / Background</td><td>Main text colour against the page background</td></tr><tr><td>Secondary Text / Background</td><td>Supporting text colour against the page background</td></tr></tbody></table><p><strong>Alert Colours</strong></p><table tabindex="0"><thead><tr><th>Pair</th><th>What it checks</th></tr></thead><tbody><tr><td>Text / Information Alert</td><td>Text readability on information alert backgrounds</td></tr><tr><td>Text / Success Alert</td><td>Text readability on success alert backgrounds</td></tr><tr><td>Text / Warning Alert</td><td>Text readability on warning alert backgrounds</td></tr><tr><td>Text / Danger Alert</td><td>Text readability on danger alert backgrounds</td></tr></tbody></table><p>For each pair, the table shows the foreground and background colour swatches, the computed contrast ratio, and pass/fail indicators for AA Large, AA, and AAA levels.</p><h3 id="accessible-theme-suggestions" tabindex="-1">Accessible Theme Suggestions <a class="header-anchor" href="#accessible-theme-suggestions" aria-label="Permalink to “Accessible Theme Suggestions”">​</a></h3><p>If your theme has contrast issues, click the <strong>Suggest Theme</strong> button to open a dialog with three auto-generated alternatives derived from your primary colour. All suggestions are guaranteed to meet WCAG AA (4.5:1) on every contrast pair.</p><table tabindex="0"><thead><tr><th>Suggestion</th><th>Description</th></tr></thead><tbody><tr><td><strong>Accessible fix</strong> <em>(recommended)</em></td><td>Your existing palette with only the failing colours adjusted to meet contrast requirements</td></tr><tr><td><strong>Warm complement</strong></td><td>A darker secondary creates visual separation from the primary colour, with a lighter background</td></tr><tr><td><strong>High contrast</strong></td><td>Deeper tones on a white background for maximum readability</td></tr></tbody></table><p>Each suggestion includes a live preview. Select one and click <strong>Try out</strong> to apply it — you can continue to fine-tune before saving.</p><h3 id="saving-with-accessibility-issues" tabindex="-1">Saving with Accessibility Issues <a class="header-anchor" href="#saving-with-accessibility-issues" aria-label="Permalink to “Saving with Accessibility Issues”">​</a></h3><p>When saving a theme, a confirmation dialog will appear reminding you that changes apply across all environments for the tenant. If your theme has outstanding WCAG issues, you can still save, but the accessibility score will remain visible so you can address issues later.</p>',52)])])}const p=t(s,[["render",i]]);export{u as __pageData,p as default};
